var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말, 제가 도와드릴 것이 있나요?","JPN":"本当に私がお手伝いできることがあるんですか？","ENG":"Really? There’s something that I can help you with?","TWN":"真的，有我幫得上忙的地方嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 어쩌면 이제는 자네만이 할 수 있는 일이지.","JPN":"ああ。今となっては君にしかできないことだろう。","ENG":"That is correct. In fact, you may be the only one who can help me with it now.","TWN":"當然，這個忙或許只有你能幫呢。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"남은 시간이 별로 많지 않거든.","JPN":"残された時間があまりないからね。","ENG":"You see, there isn’t a lot of time.","TWN":"現在已經沒剩多少時間，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 우리의 적들은…… 무척 강하다네.","JPN":"それに私たちの敵は……とても強い。","ENG":"Our enemies... They’re very strong.","TWN":"而且我們的敵人……非常強。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"적이요? 사장님처럼 착한 분께요?","JPN":"敵ですか？　社長のようにお優しい方に？","ENG":"Enemies? Even someone as kind as you has enemies?","TWN":"敵人？像老闆這麼好的人也會有敵人嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇다면 정말 나쁜 사람들이겠네요.","JPN":"だとしたら、本当に悪い人たちに違いありませんね。","ENG":"Then they must be very bad people.","TWN":"那對方應該真的很壞吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그냥 나쁜 사람들과는 조금 다르다네.","JPN":"ハハ、単に悪い人というのとは少し違うんだ。","ENG":"Haha, they are more than just \\"bad people\\".","TWN":"哈哈，他們和一般認知的壞人不太一樣，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그들은 마왕, 혹은 악마라고 불리는 초월적인 존재들이니까.","JPN":"やつらは魔王、あるいは悪魔と呼ばれる超越的な存在だからね。","ENG":"They are transcendent beings called demon lords, or devils.","TWN":"他們是被稱為魔王或惡魔的超自然存在。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마왕이요?","JPN":"魔王ですか？","ENG":"Demon lords?","TWN":"魔王嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"신기해라. 마치 동화 속 이야기 같아요.","JPN":"不思議。まるで童話の中のお話みたいです。","ENG":"That’s so interesting. It’s like something out of a fairy tale.","TWN":"好奇妙喔，好像童話故事一樣。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋은 비유로군.","JPN":"いい例えだ。","ENG":"That’s a good analogy.","TWN":"這個說法不錯。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 지아 양, 동화에서 마왕을 쓰러트리기 위해서는 뭐가 필요하겠나?","JPN":"それでは、ユイさん。童話で魔王を倒すためには何が必要かな？","ENG":"So, Miss Jia, what do the heroes in fairy tales need for defeating demon lords?","TWN":"沈佳，那我問你，在童話故事中，打倒魔王需要什麼呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"음…… 보통은 마법의 검이나 신비한 무기 아닐까요?","JPN":"う～ん……一般的には魔法の剣とか神秘的な武器でしょうか？","ENG":"Hmm... Wouldn’t it usually be a magical sword or mystical weapon?","TWN":"嗯……通常不是魔劍，就是秘密武器吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 그것일세.","JPN":"まさにそれだ。","ENG":"That’s exactly what we need.","TWN":"沒錯，就是那個！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그런 무기들은 오직 특별한 존재, 주인공만이 사용할 수 있지.","JPN":"だが、そんな武器は特別な存在である主人公だけが使えるものだ。","ENG":"However, weapons like that can only be used by special beings, which are the main heroes.","TWN":"不過那個武器很特別，只有主角能夠使用。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 현실은 동화와는 달라서, 아주 많은 마왕이 존재한다네.","JPN":"そして現実は童話とは違って、あまたの魔王が存在する。","ENG":"Also, reality differs from fairy tales, and there are many demon lords in our world.","TWN":"而且現實和童話故事是不一樣的，現實中有非常多的魔王。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 우리에게 필요한 건……","JPN":"だとしたら、我々に必要なのは……","ENG":"So, what we need is...","TWN":"因此我們需要的是……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"더 많은 무기로군요!","JPN":"それを超える数の武器ですね！","ENG":"More weapons!","TWN":"更多的武器！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 특별하고, 마법적인, 아주 많은 무기.","JPN":"そうだ。特別で、魔法的で、数多くの武器。","ENG":"Exactly. A lot of special and magical weapons.","TWN":"沒錯！很多特別又有魔法的武器。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이건…… 얼터니움이라는 신물질일세.","JPN":"これは……オルタニウムという新物質だ。","ENG":"This… is a new substance called Alternium.","TWN":"這是……稱為黑化永恆之金的新物質。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"와, 반짝반짝 예쁜 색깔이에요.","JPN":"わあ、キラキラしていて美しい色ですね。","ENG":"Wow, it has such a shiny and pretty color.","TWN":"哇，閃閃發光，好美的樣子。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"보고만 있어도 왠지 마음이 편안해지네요. 뭐든 할 수 있을 것 같은 기분이 들어요.","JPN":"見ているだけでなんだか心が休まります。何でもできるような気がしてきますね。","ENG":"Just looking at it makes me feel calmer. I feel like I can do anything.","TWN":"光是看到它就覺得心情變得很平靜，有種無所不能的感覺。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. <color=#ffd34c>기적</color>의 결정체이자 인간이 초월자에게 대항할 수 있는 최소한의 수단.","JPN":"ああ。<color=#ffd34c>奇跡</color>の結晶体であり、人間が超越者に抵抗できるせめてもの手段。","ENG":"That’s right. It’s a crystallized <color=#ffd34c>miracle</color> and the bare minimum that humanity should prepare in order to fight against those transcendent beings.","TWN":"沒錯，它是<color=#ffd34c>奇蹟</color>的結晶體，也是人類對抗超能者的手段。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 보다시피 양은 한정적이고, 입수할 수 있는 방법도 제약이 많아.","JPN":"しかし、見てのとおり量に限りがあって、入手できる方法にも制約が多い。","ENG":"However, as you can see, we only have a limited amount and it's challenging to acquire.","TWN":"但它的數量是有限的，而且取得的管道也非常受限。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지아 양, 자네의 사명은……","JPN":"ユイさん、あなたの使命は……","ENG":"Jia, your duty is...","TWN":"因此沈佳，你的使命就是……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"죄송해요. 거절할게요.","JPN":"すいません。お断りします。","ENG":"I’m sorry, but I’ll have to decline.","TWN":"老闆對不起，我拒絕。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 얼터니움을 여러 사람이 활용할 수 있는 수단을 알파트릭스 그룹이 마련해야 한다는 거죠?","JPN":"このオルタニウムを何人もの人が活用できる手段をアルファトリックスグループが用意しないといけないということでしょう？","ENG":"You want to say that the Alphatrix group needs to provide the means for several people to use this Alternium, right?","TWN":"老闆的意思是要我們阿爾法崔克斯集團，想辦法讓許多人都可以使用這個黑化永恆之金吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스 그룹은 뭐든지 대량 생산할 수 있는 시설도, 기술도 준비되어 있으니까요.","JPN":"アルファトリックスグループは何でも大量生産できる施設も、技術も揃っていますから。","ENG":"Since the Alphatrix group already has the facilities and technologies for mass producing anything.","TWN":"因為阿爾法崔克斯集團兼具可以大量生產任何東西的設備與技術。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 이 세계를 지키기 위해서는 꼭 이 얼터니움이……","JPN":"そうだ。この世界を守るために必ずこのオルタニウムが……","ENG":"That is correct. In order to protect this world, this Alternium must be...","TWN":"沒錯，要守護這個世界就需要黑化永恆之金……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>사명</color>이라거나, <color=#ffd34c>해야 한다</color>는 식의 말은 받아들일 수가 없어요.","JPN":"でも、<color=#ffd34c>使命</color>とか、<color=#ffd34c>しなければならない</color>といった言葉は承諾できません。","ENG":"However, I cannot accept that it is my <color=#ffd34c>duty</color> or that I am <color=#ffd34c>obligated</color> to do so.","TWN":"但我不能接受<color=#ffd34c>使命</color>，或是<color=#ffd34c>任務</color>的說法。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그건 저를 믿어 준 이노베이션 분들에게……","JPN":"それは私を信じてくれるイノベーションの方たちと……","ENG":"Because that will be betraying my colleagues at Innovation who trust me...","TWN":"這對相信我的夥伴們……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 저를 도와 준 사장님께 너무 못된 짓일 테니까요.","JPN":"私を助けてくださった社長にもとても申し訳ないことですから。","ENG":"And you, who helped me so much.","TWN":"還有對幫助我的老闆，都太過失禮。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 사장님의 친구로서, 사장님을 돕기 위해서라면……","JPN":"ですが、社長のお友達として、社長をお手伝いするためなら……","ENG":"However, if you are asking me as a friend to help you...","TWN":"不過若是以老闆朋友的身分來幫助老闆的話……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"설령 어떤 이득도 없고, 어떤 위기에 처하더라도 지아가 있는 힘껏 도와 드릴게요.","JPN":"たとえ何の利益もなく、どんな危機にさらされることになったとしても、ユイができる限りお手伝いいたします。","ENG":"Even if there is no benefit to me, whatever dangers may lie ahead, I, Jia, will help you with everything that I’ve got.","TWN":"就算沒有任何好處，就算會遇到危險，我都願意盡全力幫忙。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까 제게 말씀해 주세요.","JPN":"ですから、私に仰せつけください。","ENG":"So, please tell me.","TWN":"所以我只要老闆一句話，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그저, 부탁한다고.","JPN":"ただ、頼む、と。","ENG":"That you’re asking for a favor.","TWN":"說\\"拜託\\"就好。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……고맙네, 지아 양.","JPN":"……ありがとう、ユイさん。","ENG":"...Thank you, Jia.","TWN":"……謝謝你，沈佳。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부탁이니, 나를 도와 주겠나?","JPN":"頼む、私を助けてくれないか？","ENG":"Will you help me?","TWN":"拜託你，可以幫我嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들, 괜찮은가?","JPN":"みんな、無事か？","ENG":"Is everyone okay?","TWN":"大家沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어머, 힐데 소대장님 아니세요?","JPN":"あら、ヒルデ小隊長じゃないですか？","ENG":"Oh my? Is that you, Commander Hilde?","TWN":"哇喔，這不是希爾德小隊長嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이쪽은 저희 알트 소대가 벌써 잘 정리했답니다.","JPN":"こっちはアルト小隊がすでに片付けました。","ENG":"ALT Squad has already cleared this area.","TWN":"這裡我們阿爾特小隊都處理好咧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알파트릭스 신지아 회장님의 신변도 안전하게 보호했고요.","JPN":"アルペリックスのヒメノ・ユイ会長の身辺の安全も確保しましたし。","ENG":"We have also secured Alphatrix President Shin Jia’s safety.","TWN":"阿爾法崔克斯沈佳會長的人身安全也無虞。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희들만으로 탐식자의…… 아니, 놈들을 물리쳤다고?","JPN":"お前たちだけで貪食者の……いや、あいつらを退けたのか？","ENG":"Are you saying that you defeated the Devourer’s... I mean, the hostiles by yourselves?","TWN":"就你們幾個人將貪食者的……將那些傢伙處理掉嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 꿍꿍이지? 이렇게 쉽게 물러날 녀석들이 아닌데……","JPN":"なにか企んでいるのか？　こんなに簡単に退くやつらじゃないんだが……","ENG":"What are they up to? They aren’t the ones to back off this easily...","TWN":"在打什麼主意？那些傢伙應該沒這麼好對付才對……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후훗, 아무리 힐데 소대장님이라고 해도 저흴 너무 얕보시는 거 아닌가요?","JPN":"ふふっ、ヒルデ小隊長は私たちを甘く見過ぎているんじゃないですか？","ENG":"Ha ha, even for you, Commander Hilde, perhaps you're underestimating our abilities?","TWN":"呵呵，就算你是希爾德小隊長，也不能這麼瞧不起人吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"애초에 대부분의 적들은 펜릴 소대가 유인했잖아요?","JPN":"もとより敵の大部分はフェンリル小隊がおびき寄せたものでしょう？","ENG":"I mean, most of the hostiles were lured away by Fenrir Squad from the start.","TWN":"打從一開始，大部分的敵人不都是芬里爾小隊引來的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희들이 이 정도도 처리 못할 정도로 약하진 않아요.","JPN":"私たちはこの程度も処理できないほど弱くはありません。","ENG":"We’re capable of handling a force this size.","TWN":"我們小隊沒有弱到連這種程度都無法處理好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 뜻은 아니었지만…… 알겠다.","JPN":"そういう意味で言ったわけではないのだが……わかった。","ENG":"That wasn’t what I was implying... but okay.","TWN":"我不是那個意思……就這樣吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"와, 작업에 집중하고 있던 사이에 손님들이 더 늘어나셨네요.","JPN":"わあ、作業に没頭している間にお客様が増えましたね。","ENG":"Whoa, it seems that while I was focused on the work, more guests arrived.","TWN":"哇，在我忙著做事的時候，客人又增加啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"처음 보는 분들께는 인사를 드려야 한다고 배웠지만……","JPN":"お初にお目にかかる方にはご挨拶をしなくてはならないと教わりましたが……","ENG":"Although I have been taught to greet those that I’m meeting for the first time...","TWN":"初次見面應該要好好打聲招呼的……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금은 사장님이 부탁하신 일부터 마무리해야 할 것 같아요.","JPN":"今は社長から頼まれた仕事を先に片付けなくてはなりませんね。","ENG":"I’m afraid that I must prioritize the task that the Boss has requested to me.","TWN":"但我現在要先完成老闆拜託我的事情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 받으세요. 시제품을 기반으로 오비탈 베이스에서 양산에 성공한 얼터니움 리액터에요.","JPN":"さあ、お受け取りください。市販の商品をベースにオービタルベースで量産に成功した、オルタニウムリアクターです。","ENG":"Here, please take this. This is an Alternium Reactor that has been successfully mass produced on the Orbital Base based on the prototype.","TWN":"拿去吧，這是以試用品為範本，成功在軌道基地量產的黑化永恆之金電抗器。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"얼터니움 리액터?","JPN":"オルタニウムリアクター？","ENG":"Alternium Reactor?","TWN":"黑化永恆之金電抗器？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 허신과의 전투는…….","JPN":"はい。虚神との戦闘は……","ENG":"Yes. During the battle against the Hollow God...","TWN":"對，這是和幻神戰鬥……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 기밀 사항이라서 못 들으셨으려나요?","JPN":"あ、機密事項なのでお聞きにならなかったですか？","ENG":"Ah, perhaps you have not been informed of this due to it being classified?","TWN":"你沒聽說嗎？可能因為這是機密吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 리액터는 사용자에게 신, 혹은 초월자들과 싸울 수 있는 힘을 부여해 줘요.","JPN":"このリアクターは使用者に神もしくは超越者と戦うことのできる力を与えてくれます。","ENG":"This reactor gives the wielder the power to fight gods or transcendent beings.","TWN":"這個電抗器會賦予使用者，足以對抗神或是超能力者的力量。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"특히 서윤 씨가 지닌 미스틸테인의 비어 있는 심장을 채우기에 안성맞춤이죠.","JPN":"特に、アオイさんが持っているミスティルテインの空いている心臓部を埋めるのにぴったりです。","ENG":"For example, it would be a perfect fit inside the empty heart of your Misteltein.","TWN":"尤其徐芸小姐那把米斯特汀是空心的，正適合拿來裝在上面呢。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님이 서윤 씨를 보내신 이유도 그것 때문일 거예요.","JPN":"社長がアオイさんを送った理由もそこにあると思います。","ENG":"That may be the reason why your boss sent you here.","TWN":"我想老闆之所以會派你來，應該也是因為這個原因吧。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미스틸테인의 심장을……?","JPN":"ミスティルテインの心臓を……？","ENG":"Misteltein’s... heart?","TWN":"裝在米斯特汀的心臟位置……？"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 물론 그런 테크 레벨 5의 장비 프레임이 없더라도 유용해요.","JPN":"はい、もちろんそういったテックレベル5の装備フレームが無くても使えます。","ENG":"Yes. Of course, it’s still useful even without a Tech Level 5 gear frame.","TWN":"沒錯，不過就算沒有那種技術等級5的裝備外殼，也不會影響它本身的效能。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그저 이 얼터니움 리액터를 장착하는 것만으로도 일반적인 카운터의 등급을 한 단계, 어쩌면 두 단계 이상 높이는 것도 가능하죠.","JPN":"このオルタニウムリアクターを装着するだけでも、一般的なカウンターの等級を1段階、ともすれば2段階以上あげることができます。","ENG":"Just by equipping this Alternium Reactor, a regular Counter’s grade will be raised by one, or even perhaps two grades.","TWN":"只要裝上黑化永恆之金電抗器，就可以使一般制裁者的等級提升一階，或甚至是兩階以上。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"서윤 씨의 동료들에게도 큰 힘이 될 거예요.","JPN":"アオイさんの同僚の方々にとっても大きな力になると思います。","ENG":"It’ll also be of great use to your colleagues, Miss Seo Yoon.","TWN":"相信對你的同事也會很有幫助的。"},"stage":{"bg":"MAINSTREAM_803","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"왜 이런 걸 덥석 만들어 주는 거죠? 회장님에게도 이걸 만드는 게 보통 일은 아닌 것 같은데요?","JPN":"なんでこんなものを素直に作ってくれるんですか？　会長にとってもこれを作るのは簡単じゃないと思いますが。","ENG":"Why did you just agree to make something like this? Even if it’s you, making this wouldn’t have been an easy task.","TWN":"為什麼要突然做這種東西給我？這對會長而言應該也不是那麼簡單的事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그야 사장님께 부탁 받았으니까요.","JPN":"それは社長の頼みだからです。","ENG":"Well, that’s because the Boss asked me for a favor.","TWN":"因為是老闆拜託我的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전 이걸 더 많이 만들 거예요. 모든 사람이 가질 수 있게.","JPN":"これをもっとたくさん作って、すべての人が持てるようにします。","ENG":"I’m going to make more of these, so that everyone will be able to have one.","TWN":"我會再多做一點，讓大家都可以使用。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 사장님께서 원하는 기적을 이룰 수 있도록 도움을……","JPN":"だから社長が望む奇跡を起こせるように、お手伝いを……","ENG":"That way, I can help him achieve the miracle that he─","TWN":"因此希望老闆說的奇蹟可以……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"응? 이건 무슨 소리죠?","JPN":"え？　何の音でしょう？","ENG":"Huh? What was that?","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연, 방금 충격으로 함선 궤도가 뒤틀린 것 같다!","JPN":"カナミ、今の衝撃で艦船の軌道がずれたようだ！","ENG":"Lee Sooyeon, I think the ship’s orbit has been altered by the collision just now!","TWN":"李秀妍，剛剛的衝擊似乎導致艦船的航道改變！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"상황 확인 가능한가?","JPN":"現状確認はできるか？","ENG":"Can you check the situation?","TWN":"你能確認情況嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공간을 넘어서 나타난 거대한 촉수가…… 오비탈 베이스를 휘감고 있습니다!","JPN":"空間を超えて現れた巨大な触手が……オービタルベースに巻きついています！","ENG":"A gigantic tentacle warped through space and is now wrapping itself around the Orbital Base!","TWN":"有股超越空間出現的勢力……正包圍著軌道基地！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 오비탈 베이스를 통째로 끌고 가려는 것 같군요.","JPN":"どうやらオービタルベースを丸ごと引っ張って行くつもりのようです。","ENG":"It seems that it’s trying to drag the Orbital Base back with it.","TWN":"似乎是想將軌道基地整個拖走！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이런…… 하수인들을 보낸 것도 날 여기로 유인하려는 계략이었나.","JPN":"そんな……手下を送ったのも私をここに誘うための策だったのか。","ENG":"Ugh... Sending her minions must have been a ploy to lure me here.","TWN":"可惡……難道是調虎離山之計？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 나가려면 시간이 걸린다. 그쪽에서 대응할 수 있겠나?","JPN":"私が脱出するには時間がかかる。そっちで対応できるか？","ENG":"It’ll take me some time to get out there. Can you handle it from your end?","TWN":"我出去的話太浪費時間，你那邊能應付嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저건 학부장급도 아니고 마왕이 직접 행사하는 권능이에요. 불가능합니다.","JPN":"あれは学部長レベルではなく、魔王が直接行使している権能です。できません。","ENG":"Negative. It’s not some dean using this power. It’s a Demon Lord controlling it directly.","TWN":"對方不是教授等級，是魔王親自出手，我沒辦法應付。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"단기전으로 대응 가능한 건 울브즈베인을 가진 미나 양뿐입니다.","JPN":"短期的に対応可能なのはウルブズベインを持っているミナさんだけです。","ENG":"The only one who will be able to hold it off temporarily will be Mina with her Wolvesbane.","TWN":"目前暫時能應付的，就只有擁有狼之災禍的米娜。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"안 돼. 녀석이 직접 마왕과 마주치면 게임이 최종 국면으로 넘어가 버릴 수도 있어.","JPN":"だめだ。あいつが直接魔王に対すればゲームが最終局面に突入しかねない。","ENG":"No. If she directly confronts a Demon Lord, the game may skip to the final showdown.","TWN":"不行，萬一那傢伙直接和魔王交手，恐怕遊戲會直接走向最終結局。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"놈들의 속셈이 뭔지 모르는 이상 그건 너무 위험하다.","JPN":"やつらの企みが何であるかわからない以上、それは危険すぎる。","ENG":"Until we have an idea of what they’re up to, it’s too risky.","TWN":"現在還不清楚對方在打什麼算盤，那麼做的風險太大。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 오비탈 베이스를 포기하는 건 어떻습니까?","JPN":"ではオービタルベースを諦めるのはどうでしょうか？","ENG":"How about abandoning the Orbital Base?","TWN":"那還是放棄軌道基地呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"That’s...","TWN":"這個嘛……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니. 역시 포기할 수 없다. 여기서 뭔가 재미있는 걸 만들고 있더군.","JPN":"いや。やはり諦めるわけにはいかない。ここで何かおもしろいものを作っていたんだ。","ENG":"No, that’s out of the question. They seem to be making something interesting on this ship.","TWN":"不，沒辦法，這裡似乎正在製造有趣的東西。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"얼터니움이라고 하던가?","JPN":"オルタニウムと言ったか？","ENG":"Alternium, you said?","TWN":"好像是叫黑化永恆之金的東西？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내 기억에는 없는 물질이지만, 저런 괴상한 걸 만들 수 있는 자가 누구인지는 뻔하지.","JPN":"私の記憶にはない物質だが、あんな奇怪なものを作れる者はあいつぐらいだろう。","ENG":"It’s not a substance that I remember, but there’s only one person who could make such a bizarre thing.","TWN":"雖然我沒印象有這種的東西，不過想也知道誰有能耐做出那種詭異的東西。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석이 준비해 둔 물건이라면 쉽게 포기할 수는 없다.","JPN":"あいつが用意したものなら簡単に諦めるわけにはいかない。","ENG":"If this is something that he prepared, then we must secure it at all costs.","TWN":"若是那傢伙準備的，那就不能輕易放棄。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"일단 놈들이 원하는 대로 하게 놔두도록. 대응은 그 후에 한다.","JPN":"とりあえずやつらがやりたいように放っておけ。対応はその後にする。","ENG":"Let’s let them do whatever they want for now. We’ll take action later.","TWN":"就先任由他們去吧，等之後再想辦法。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 좌표 계산 결과, 오비탈 베이스가 끌려들어가는 곳은……","JPN":"わかりました。座標計算の結果、オービタルベースが引っ張られていく場所は……","ENG":"Roger that. Based on my calculations, the destination that the Orbital Base is being dragged to is...","TWN":"好吧，座標計算結果，推測軌道基地被拖往的地方是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자 전당으로 추정됩니다.","JPN":"影の殿堂とみられます。","ENG":"The Shadow Palaces.","TWN":"暗影殿堂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희도 바로 가겠습니다, 스승님. 조금만 기다려 주시길.","JPN":"私たちもすぐに行きます、師匠。少しだけお待ちを。","ENG":"We’ll also set course for there immediately, Master. Please hang in there for a while.","TWN":"我們也會立刻出發，請師父稍候。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};